qry:select.qry:xquery:
for $r in sql(' SELECT CON.d_informatica as d_informatica, C_V.c_nivel as c_nivel
FROM SDP01_INFORMATICA AS C_V, SDP08_INFORMATICA AS CON JOIN con.oi_informatica INNER c_v.oi_informatica WHERE C_V.oi_cv= {#PARAM:@id}
')/ROWS/ROW

for $r in sql(' SELECT P_CV.f_postulacion, SDP05.c_aviso, SDP05.d_puesto as d_puesto, SDP07.d_jerarquia as d_jerarquia, SDP09.d_area as d_area, loc.d_localidad as d_localidad, pro.d_provincia as d_provincia, PAIS.d_pais as d_pais, SDP05.c_sexo as c_sexo, SDP05.d_mail as d_mail, SDP05.d_mail_alt_1 as d_mail_alt_1
FROM SDP01_POSTU_CV AS P_CV, SDP05_AVISOS AS SDP05, SDP07_JERARQUIA AS SDP07, SDP09_AREAS AS SDP09, ORG19_LOCALIDADES AS LOC, ORG35_PROVINCIAS AS PRO, ORG35_PAISES AS PAIS JOIN SDP05.oi_aviso INNER P_CV.oi_aviso, SDP05.oi_jerarquia LEFT OUTER SDP07.oi_jerarquia, SDP05.oi_area LEFT OUTER SDP09.oi_area, SDP05.oi_pais LEFT OUTER PAIS.oi_pais, SDP05.oi_provincia LEFT OUTER PRO.oi_provincia, SDP05.oi_localidad LEFT OUTER LOC.oi_localidad WHERE P_CV.oi_cv= {#PARAM:@id}
')/ROWS/ROW
